// Package A: sets an early export, then requires pkg-b (which requires pkg-a back).
'use strict';

// Set an early export BEFORE requiring pkg-b
exports.name = 'pkg-a';
exports.early = 'a-early-value';

// Now require pkg-b (which will require us back, seeing only the early exports)
var pkgB = require('pkg-b');
exports.pkgB = pkgB;

// Set a late export AFTER requiring pkg-b
exports.late = 'a-late-value';
